import mysql.connector
from mysql.connector import Error

def load_data_from_file(file_path, table_name):
    try:
        # Establish a connection to the MySQL database
        connection = mysql.connector.connect(
            host='your_host',
            user='your_user',
            password='your_password',
            database='your_database',
            local_infile=True
        )

        if connection.is_connected():
            cursor = connection.cursor()
            
            # Construct the LOAD DATA INFILE statement
            query = "LOAD DATA INFILE '{}' INTO TABLE {} FIELDS TERMINATED BY ',' ENCLOSED BY '\"' LINES TERMINATED BY '\n' IGNORE 1 ROWS".format(file_path, table_name)
            
            # Execute the query
            cursor.execute(query)
            connection.commit()
            print("Data loaded successfully from file: {}".format(file_path))
    
    except Error as e:
        print("Error while connecting to MySQL", e)
    
    finally:
        if (connection.is_connected()):
            cursor.close()
            connection.close()
            print("MySQL connection is closed")

if __name__ == "__main__":
    file_path = input("Enter the path of the file to import: ")
    table_name = input("Enter the name of the table to import into: ")
    load_data_from_file(file_path, table_name)